/* eslint-disable @typescript-eslint/no-unused-vars */
import { Test, TestingModule } from '@nestjs/testing';
import { UnauthorizedException } from '@nestjs/common';
import { SignInService } from '../../services';
import { randomUUID } from 'crypto';
import { CryptoService } from './../../../../libs/crypto/services/crypto.service';
import { PrismaService } from './../../../../libs/database';
import { UsersService } from './../../../../modules/users/users.service';

describe('SignInService - Integration', () => {
  let service: SignInService;
  let prisma: PrismaService;

  beforeAll(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        SignInService,
        UsersService,
        PrismaService,
        {
          provide: CryptoService,
          useValue: {
            comparePassword: jest.fn((plain: string, hashed: string) =>
              Promise.resolve(plain === hashed.replace('hashed-', '')),
            ),
            signJwt: jest.fn(
              (payload: { sub: number }) =>
                `jwt-${payload.sub}-${randomUUID()}`,
            ),
          },
        },
      ],
    }).compile();

    service = module.get<SignInService>(SignInService);
    prisma = module.get<PrismaService>(PrismaService);

    // Limpar dados
    await prisma.user.deleteMany();
  });

  afterAll(async () => {
    await prisma.$disconnect();
  });

  it('should sign in successfully with correct credentials', async () => {
    const user = await prisma.user.create({
      data: {
        firstname: 'Alice',
        lastname: 'Smith',
        nickname: 'alice123',
        email: 'alice@example.com',
        password: 'hashed-password', // será validado pelo mock
      },
    });

    const result = await service.execute('alice@example.com', 'password');

    expect(result.accessToken).toBeDefined();
    expect(result.refreshToken).toBeDefined();
    expect(result.user).toMatchObject({
      id: user.id,
      firstname: user.firstname,
      lastname: user.lastname,
      nickname: user.nickname,
      email: user.email,
    });

    // Verifica se refreshToken foi atualizado no banco
    const updatedUser = await prisma.user.findUnique({
      where: { id: user.id },
    });
    expect(updatedUser!.refreshToken).toBe(`hashed-${result.refreshToken}`);
  });

  it('should throw UnauthorizedException for incorrect password', async () => {
    const user = await prisma.user.create({
      data: {
        firstname: 'Bob',
        lastname: 'Johnson',
        nickname: 'bob123',
        email: 'bob@example.com',
        password: 'hashed-password',
      },
    });

    await expect(
      service.execute('bob@example.com', 'wrongpassword'),
    ).rejects.toThrow(UnauthorizedException);
  });

  it('should throw UnauthorizedException for non-existing email', async () => {
    await expect(
      service.execute('nonexistent@example.com', 'password'),
    ).rejects.toThrow(UnauthorizedException);
  });

  it('should throw UnauthorizedException for user without password', async () => {
    const user = await prisma.user.create({
      data: {
        firstname: 'Charlie',
        lastname: 'Brown',
        nickname: 'charlie123',
        email: 'charlie@example.com',
        password: '',
      },
    });

    await expect(service.execute('charlie@example.com', 'any')).rejects.toThrow(
      UnauthorizedException,
    );
  });
});
